sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

    // Get the value of Access field
    var accessValue = g_form.getValue('acess');

    // If Access has a value, make Email mandatory
    if (accessValue != '') {
        g_form.setMandatory('name', true);
        g_form.showFieldMsg('name', 'Name is required when Access is selected', 'info');
    } else {
        // If Access is cleared, Email is no longer mandatory
        g_form.setMandatory('name', false);
        g_form.hideFieldMsg('name');
    }
}
